form:Form.form:Scripts:
		//Generar la lista de Numeros
function WhereNros()
{                      
	var listNros,Where,t,subTxt,aux0,aux1;

 	Where="";

	listNros=Ctrl('listNros').GetXValue();
	if (listNros!="")
	{
		listNros=Replace(listNros,",",";").split(";");

		for (t=0; t<listNros.length; t++)
		{ 
			if (listNros[t].indexOf("-")>=0)
			{  
				subTxt=listNros[t].split("-");
				aux0=parseInt(subTxt[0],10);
				aux1=parseInt(subTxt[1],10);

     		if ((!isNaN(aux0)) || (!isNaN(aux1)))
     		{
	     		if (Where!="") Where+=" OR ";
					Where+="(";
						if (!isNaN(aux0)) Where+="STRING2NUMBER(CAR.oi_carpeta) >="+aux0;
						if ((!isNaN(aux0)) && (!isNaN(aux1))) Where+=" AND ";
						if (!isNaN(aux1)) Where+="STRING2NUMBER(CAR.oi_carpeta) <="+aux1;
					Where+=")";
				}
			} else
			{                           
				aux0=parseInt(listNros[t],10);
				if (!isNaN(aux0)) 
				{
					if (Where!="") Where+=" OR ";
					Where+="STRING2NUMBER(CAR.oi_carpeta)="+ aux0;
				}
			}
		}
	}

	if (Where=="" && Ctrl('listNros').GetXValue()!="") Where="1=2";
	Ctrl("nrosWhere").SetXValue(Where);
	//exec_qry();
}

//Generar la lista de Códigos
function WhereCods()
{                      
	var listCods,Where,t,subTxt,aux0,aux1;

 	Where="";

	listCods=Ctrl('listCods').GetXValue();
	if (listCods!="")
	{
		listCods=Replace(listCods,",",";").split(";");

		for (t=0; t<listCods.length; t++)
		{ 
			if (listCods[t].indexOf("-")>=0)
			{  
				subTxt=listCods[t].split("-");
				aux0=parseInt(subTxt[0],10);
				aux1=parseInt(subTxt[1],10);

     		if ((!isNaN(aux0)) || (!isNaN(aux1)))
     		{
	     		if (Where!="") Where+=" OR ";
					Where+="(";
						if (!isNaN(aux0)) Where+="STRING2NUMBER(CAR.c_carpeta) >="+aux0;
						if ((!isNaN(aux0)) && (!isNaN(aux1))) Where+=" AND ";
						if (!isNaN(aux1)) Where+="STRING2NUMBER(CAR.c_carpeta) <="+aux1;
					Where+=")";
				}
			} else
			{                           
				aux0=parseInt(listCods[t],10);
				if (!isNaN(aux0)) 
				{
					if (Where!="") Where+=" OR ";
					Where+="STRING2NUMBER(CAR.c_carpeta)="+ aux0;
				}
			}
		}
	}

	if (Where=="" && Ctrl('listCods').GetXValue()!="") Where="1=2";
	Ctrl("codsWhere").SetXValue(Where);
	//exec_qry();
}

function FILTRAR()
{
	Ctrl("main").DoEvent("FILTER");
}

qry:select.qry:xquery:
		for $r in SQL('
	SELECT
		COUNT(QYR01_RECLAMOS.oi_reclamo) as cantidad
	FROM
		QYR01_RECLAMOS
	WHERE
		{%? (#PARAM:@id ='PEN') 
			{% QYR01_RECLAMOS.c_estado != \'Reclamo finalizado\'	%}  
			{% 
				{%? (#PARAM:@id ='CER') 
				{% QYR01_RECLAMOS.c_estado = \'Reclamo finalizado\'	%}  
				{% 1=1  %} 
				%}
			%} 
		%}
')/ROWS/ROW
